**Notification hook file (e.g., `useNotification.ts`):**

```typescript
import { createContext, useContext, useState } from 'react';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

interface NotificationContextInterface {
  openNotification: (props: NotificationProps) => void;
}

const NotificationContext = createContext<NotificationContextInterface | null>(null);

const useNotification = () => {
  const notificationContext = useContext(NotificationContext);
  if (!notificationContext) {
    throw new Error('useNotification must be used within a NotificationContext');
  }

  const openNotification = async (props: NotificationProps) => {
    if (!notificationContext) return;

    const { heading, subheading, type } = props;
    try {
      await notificationContext.open({
        heading,
        subheading,
        type,
      });
    } catch (error) {
      console.error(error);
    }
  };

  return { openNotification };
};

export { NotificationContext, useNotification };
```

